Implementation file: src/game-of-life.ts
Passing tests: 5
Recent changes: Added birth/reproduction logic - find dead neighbor candidates, count their live neighbors, include those with exactly 3.

Current implementation:
```typescript
const countNeighbors = (x: number, y: number, alive: Set<string>): number => {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (alive.has(`${x + dx},${y + dy}`)) count++;
    }
  }
  return count;
};

export const nextGeneration = (grid: number[][]): number[][] => {
  const alive = new Set(grid.map(([x, y]) => `${x},${y}`));
  const survivors = grid.filter(([x, y]) => {
    const neighbors = countNeighbors(x, y, alive);
    return neighbors === 2 || neighbors === 3;
  });
  const candidates = new Set<string>();
  for (const [x, y] of grid) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        if (!alive.has(key)) candidates.add(key);
      }
    }
  }
  const births: number[][] = [];
  for (const key of candidates) {
    const [x, y] = key.split(",").map(Number);
    if (countNeighbors(x, y, alive) === 3) births.push([x, y]);
  }
  return [...survivors, ...births];
};
```

Note: The candidate-finding loop duplicates the neighbor iteration pattern from countNeighbors. Consider whether extracting a shared neighbor coordinate generator or similar refactoring would improve clarity.

